		return "record"
	elseif kind == SyntaxKind.ManagedKeyword then
		return "managed"
	elseif kind == SyntaxKind.UnmanagedKeyword then
		return "unmanaged"
	elseif kind == SyntaxKind.RequiredKeyword then
		return "required"
	elseif kind == SyntaxKind.ScopedKeyword then
		return "scoped"
	elseif kind == SyntaxKind.FileKeyword then
		return "file"
	elseif kind == SyntaxKind.AllowsKeyword then
		return "allows"
	elseif kind == SyntaxKind.ExtensionKeyword then
		return "extension"
	end
	return ""
end

function SyntaxFacts.GetText_Accessibility(accessibility: number): string
	if accessibility == 0 then
		return ""
	elseif accessibility == 1 then
		return SyntaxFacts.GetText(SyntaxKind.PrivateKeyword)
	elseif accessibility == 2 then
		return SyntaxFacts.GetText(SyntaxKind.PrivateKeyword) .. " " .. SyntaxFacts.GetText(SyntaxKind.ProtectedKeyword)
	elseif accessibility == 4 then
		return SyntaxFacts.GetText(SyntaxKind.InternalKeyword)
	elseif accessibility == 3 then
		return SyntaxFacts.GetText(SyntaxKind.ProtectedKeyword)
	elseif accessibility == 5 then
		return SyntaxFacts.GetText(SyntaxKind.ProtectedKeyword) .. " " .. SyntaxFacts.GetText(SyntaxKind.InternalKeyword)
	elseif accessibility == 6 then
		return SyntaxFacts.GetText(SyntaxKind.PublicKeyword)
	end
	return (function() error(ArgumentOutOfRangeException.new("accessibility")) end)()
end

function SyntaxFacts.GetOperatorKind(operatorMetadataName: string): number
	if operatorMetadataName == "op_CheckedAddition" or operatorMetadataName == "op_Addition" then
		return SyntaxKind.PlusToken
	elseif operatorMetadataName == "op_BitwiseAnd" then
		return SyntaxKind.AmpersandToken
	elseif operatorMetadataName == "op_BitwiseOr" then
		return SyntaxKind.BarToken
	elseif operatorMetadataName == "op_Decrement" or operatorMetadataName == "op_CheckedDecrement" or operatorMetadataName == "op_CheckedDecrementAssignment" or operatorMetadataName == "op_DecrementAssignment" then
		return SyntaxKind.MinusMinusToken
	elseif operatorMetadataName == "op_CheckedDivision" or operatorMetadataName == "op_Division" then
		return SyntaxKind.SlashToken
	elseif operatorMetadataName == "op_Equality" then
		return SyntaxKind.EqualsEqualsToken
	elseif operatorMetadataName == "op_ExclusiveOr" then
		return SyntaxKind.CaretToken
	elseif operatorMetadataName == "op_CheckedExplicit" or operatorMetadataName == "op_Explicit" then
		return SyntaxKind.ExplicitKeyword
	elseif operatorMetadataName == "op_False" then
		return SyntaxKind.FalseKeyword
	elseif operatorMetadataName == "op_GreaterThan" then
		return SyntaxKind.GreaterThanToken
	elseif operatorMetadataName == "op_GreaterThanOrEqual" then
		return SyntaxKind.GreaterThanEqualsToken
	elseif operatorMetadataName == "op_Implicit" then
		return SyntaxKind.ImplicitKeyword
	elseif operatorMetadataName == "op_Increment" or operatorMetadataName == "op_CheckedIncrement" or operatorMetadataName == "op_CheckedIncrementAssignment" or operatorMetadataName == "op_IncrementAssignment" then
		return SyntaxKind.PlusPlusToken
	elseif operatorMetadataName == "op_Inequality" then
		return SyntaxKind.ExclamationEqualsToken
	elseif operatorMetadataName == "op_LeftShift" then
		return SyntaxKind.LessThanLessThanToken
	elseif operatorMetadataName == "op_LessThan" then
		return SyntaxKind.LessThanToken
	elseif operatorMetadataName == "op_LessThanOrEqual" then
		return SyntaxKind.LessThanEqualsToken
	elseif operatorMetadataName == "op_LogicalNot" then
		return SyntaxKind.ExclamationToken
	elseif operatorMetadataName == "op_Modulus" then
		return SyntaxKind.PercentToken
	elseif operatorMetadataName == "op_CheckedMultiply" or operatorMetadataName == "op_Multiply" then
		return SyntaxKind.AsteriskToken
	elseif operatorMetadataName == "op_OnesComplement" then
		return SyntaxKind.TildeToken
	elseif operatorMetadataName == "op_RightShift" then
		return SyntaxKind.GreaterThanGreaterThanToken
	elseif operatorMetadataName == "op_UnsignedRightShift" then
		return SyntaxKind.GreaterThanGreaterThanGreaterThanToken
	elseif operatorMetadataName == "op_Subtraction" or operatorMetadataName == "op_CheckedSubtraction" then
		return SyntaxKind.MinusToken
	elseif operatorMetadataName == "op_True" then
		return SyntaxKind.TrueKeyword
	elseif operatorMetadataName == "op_CheckedUnaryNegation" or operatorMetadataName == "op_UnaryNegation" then
		return SyntaxKind.MinusToken
	elseif operatorMetadataName == "op_UnaryPlus" then
		return SyntaxKind.PlusToken
	elseif operatorMetadataName == "op_AdditionAssignment" or operatorMetadataName == "op_CheckedAdditionAssignment" then
		return SyntaxKind.PlusEqualsToken
	elseif operatorMetadataName == "op_DivisionAssignment" or operatorMetadataName == "op_CheckedDivisionAssignment" then
		return SyntaxKind.SlashEqualsToken
	elseif operatorMetadataName == "op_CheckedMultiplicationAssignment" or operatorMetadataName == "op_MultiplicationAssignment" then
		return SyntaxKind.AsteriskEqualsToken
	elseif operatorMetadataName == "op_CheckedSubtractionAssignment" or operatorMetadataName == "op_SubtractionAssignment" then
		return SyntaxKind.MinusEqualsToken
	elseif operatorMetadataName == "op_ModulusAssignment" then
		return SyntaxKind.PercentEqualsToken
	elseif operatorMetadataName == "op_BitwiseAndAssignment" then
		return SyntaxKind.AmpersandEqualsToken
	elseif operatorMetadataName == "op_BitwiseOrAssignment" then
		return SyntaxKind.BarEqualsToken
	elseif operatorMetadataName == "op_ExclusiveOrAssignment" then
		return SyntaxKind.CaretEqualsToken
	elseif operatorMetadataName == "op_LeftShiftAssignment" then
		return SyntaxKind.LessThanLessThanEqualsToken
	elseif operatorMetadataName == "op_RightShiftAssignment" then
		return SyntaxKind.GreaterThanGreaterThanEqualsToken
	elseif operatorMetadataName == "op_UnsignedRightShiftAssignment" then
		return SyntaxKind.GreaterThanGreaterThanGreaterThanEqualsToken
	else
		return SyntaxKind.None
	end
end

function SyntaxFacts.IsCheckedOperator(operatorMetadataName: string): boolean
	if operatorMetadataName == "op_CheckedDecrement" or operatorMetadataName == "op_CheckedIncrement" or operatorMetadataName == "op_CheckedAddition" or operatorMetadataName == "op_CheckedDivision" or operatorMetadataName == "op_CheckedMultiply" or operatorMetadataName == "op_CheckedExplicit" or operatorMetadataName == "op_CheckedAdditionAssignment" or operatorMetadataName == "op_CheckedDivisionAssignment" or operatorMetadataName == "op_CheckedDecrementAssignment" or operatorMetadataName == "op_CheckedIncrementAssignment" or operatorMetadataName == "op_CheckedUnaryNegation" or operatorMetadataName == "op_CheckedSubtraction" or operatorMetadataName == "op_CheckedMultiplicationAssignment" or operatorMetadataName == "op_CheckedSubtractionAssignment" then
		return true
	else
		return false
	end
end

function SyntaxFacts.IsTypeParameterVarianceKeyword(kind: number): boolean
	if kind ~= SyntaxKind.OutKeyword then
		return kind == SyntaxKind.InKeyword
	end
	return true
end

function SyntaxFacts.IsDocumentationCommentTrivia(kind: number): boolean
	if kind ~= SyntaxKind.SingleLineDocumentationCommentTrivia then
		return kind == SyntaxKind.MultiLineDocumentationCommentTrivia
	end
	return true
end

return { SyntaxFacts = SyntaxFacts }
